INSERT INTO SHOWS (id, title, sub_title, info, start_date, end_date, view_count, sale_type, sale_start_date, sale_end_date, image, venue_id, running_minutes, performer_id, created_at, created_by, status) VALUES (1, '황문희 피아노 독주회', '예술의전당 [서울] 리사이틀홀', '예술의전당 [서울] 리사이틀홀에서 열리는 이번 클래식 무대는 약 90분 러닝타임으로 운영됩니다. 주요 레퍼토리와 앙상블의 균형을 중심으로 구성됩니다. 세부 프로그램과 출연진 변경 사항은 회차별 공지에서 확인할 수 있습니다.', '2026-03-29', '2026-03-29', 119269, 'GENERAL', '2026-02-13 10:00:00', '2026-04-28 23:59:59', 'https://kopis.or.kr/upload/pfmPoster/PF_PF286025_260227_155957.gif', 1, 90, 1, '2025-06-15 09:30:00', 'KOPIS_SEED', 'ACTIVE');
INSERT INTO SHOWS (id, title, sub_title, info, start_date, end_date, view_count, sale_type, sale_start_date, sale_end_date, image, venue_id, running_minutes, performer_id, created_at, created_by, status) VALUES (2, '성남아트센터 마티네 콘서트: 독일, 음악의 숲', '성남아트센터 콘서트홀', '성남아트센터 마티네 콘서트: 독일, 음악의 숲 공연은 성남아트센터 콘서트홀에서 진행되며, 약 100분 동안 주요 레퍼토리와 앙상블의 균형을 중심으로 구성됩니다. 예매 전 회차별 상세 안내를 확인하면 좌석 및 관람 계획을 보다 정확히 세울 수 있습니다.', '2026-03-19', '2026-12-17', 118538, 'GENERAL', '2026-02-04 10:00:00', '2027-01-16 23:59:59', 'https://kopis.or.kr/upload/pfmPoster/PF_PF285984_260227_140158.gif', 10, 100, 2, '2025-07-02 14:15:00', 'KOPIS_SEED', 'ACTIVE');
INSERT INTO SHOWS (id, title, sub_title, info, start_date, end_date, view_count, sale_type, sale_start_date, sale_end_date, image, venue_id, running_minutes, performer_id, created_at, created_by, status) VALUES (3, '독일 슈투트가르트 필하모닉 오케스트라 첫 내한공연', '롯데콘서트홀 롯데콘서트홀', '독일 슈투트가르트 필하모닉 오케스트라 첫 내한공연은 롯데콘서트홀 롯데콘서트홀에서 진행되며, 약 100분 동안 주요 레퍼토리와 앙상블의 균형을 중심으로 구성됩니다. 회차별 출연진과 세부 편성은 예매 페이지 공지를 기준으로 운영됩니다.', '2026-05-29', '2026-05-29', 117807, 'GENERAL', '2026-04-17 10:00:00', '2026-06-28 23:59:59', 'https://kopis.or.kr/upload/pfmPoster/PF_PF285958_260227_115029.png', 4, 100, 3, '2025-07-18 11:00:00', 'KOPIS_SEED', 'ACTIVE');
