INSERT INTO SHOWS (id, title, sub_title, info, start_date, end_date, view_count, sale_type, sale_start_date, sale_end_date, image, venue_id, running_minutes, performer_id, created_at, created_by, status) VALUES (79, '이종은 피아노 리사이틀', '금호아트홀 연세 금호아트홀 연세', '금호아트홀 연세 금호아트홀 연세에서 열리는 이번 클래식 무대는 약 90분 러닝타임으로 운영됩니다. 주요 레퍼토리와 앙상블의 균형을 중심으로 구성됩니다. 세부 프로그램과 출연진 변경 사항은 회차별 공지에서 확인할 수 있습니다.', '2026-03-13', '2026-03-13', 62251, 'GENERAL', '2026-02-05 10:00:00', '2026-04-12 23:59:59', 'https://kopis.or.kr/upload/pfmPoster/PF_PF285433_260220_110339.gif', 3, 90, 19, '2026-04-15 09:00:00', 'KOPIS_SEED', 'ACTIVE');
INSERT INTO SHOWS (id, title, sub_title, info, start_date, end_date, view_count, sale_type, sale_start_date, sale_end_date, image, venue_id, running_minutes, performer_id, created_at, created_by, status) VALUES (80, '이 사랑, 이 운명. 아리아로 엮는 오페라의 비망록', '세종문화회관 세종체임버홀', '이 사랑, 이 운명. 아리아로 엮는 오페라의 비망록 공연은 세종문화회관 세종체임버홀에서 진행되며, 약 90분 동안 주요 레퍼토리와 앙상블의 균형을 중심으로 구성됩니다. 예매 전 회차별 상세 안내를 확인하면 좌석 및 관람 계획을 보다 정확히 세울 수 있습니다.', '2026-03-04', '2026-03-04', 61520, 'EXCLUSIVE', '2026-01-18 10:00:00', '2026-04-03 23:59:59', 'https://kopis.or.kr/upload/pfmPoster/PF_PF285430_260220_105605.jpg', 2, 90, 20, '2026-04-20 14:30:00', 'KOPIS_SEED', 'ACTIVE');
